import { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import Card from '@/components/Card';
import { useGroups } from '@/context/GroupsContext';
import '@/styles/forms.css';

const AddExpense = () => {
    const [splitType, setSplitType] = useState('equal');
    const navigate = useNavigate();
    const location = useLocation();
    const { groups } = useGroups();

    // ❌ removed TypeScript casting
    const initialGroupId = location.state?.groupId || groups[0]?.id || '';
    const [groupId, setGroupId] = useState(initialGroupId);

    const selectedGroup = groups.find((g) => g.id === groupId);
    const members = selectedGroup?.members || ['You'];

    // ❌ removed React.FormEvent type
    const handleSubmit = (e) => {
        e.preventDefault();
        navigate('/split-summary');
    };

    return (
        <div style={{ maxWidth: 760, margin: '0 auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 24 }}>
                <div>
                    <h1 style={{ fontSize: 28, fontWeight: 800, marginBottom: 4 }}>Add Expense</h1>
                    <p style={{ fontSize: 14, color: 'var(--text-secondary)' }}>
                        Record a new shared expense and split it instantly.
                    </p>
                </div>
                <button className="btn btn-ghost" onClick={() => navigate(-1)} style={{ fontSize: 20, padding: 8 }}>✕</button>
            </div>

            <Card>
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="form-label-upper">SELECT GROUP</label>
                        <select
                            className="form-select"
                            value={groupId}
                            onChange={(e) => setGroupId(e.target.value)}
                            required
                        >
                            <option value="" disabled>Choose a group</option>
                            {groups.map((g) => (
                                <option key={g.id} value={g.id}>{g.icon} {g.name}</option>
                            ))}
                        </select>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20, marginBottom: 20 }}>
                        <div className="form-group" style={{ marginBottom: 0 }}>
                            <label className="form-label-upper">DESCRIPTION</label>
                            <input type="text" className="form-input" placeholder="Coffee, dinner, gas..." required />
                        </div>
                        <div className="form-group" style={{ marginBottom: 0 }}>
                            <label className="form-label-upper">AMOUNT</label>
                            <div style={{ position: 'relative' }}>
                                <span style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', fontWeight: 600, color: 'var(--text-secondary)' }}>₹</span>
                                <input type="number" className="form-input" placeholder="0.00" style={{ paddingLeft: 28 }} required />
                            </div>
                        </div>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20, marginBottom: 20 }}>
                        <div className="form-group" style={{ marginBottom: 0 }}>
                            <label className="form-label-upper">PAID BY</label>
                            <select className="form-select">
                                {members.map((m) => (
                                    <option key={m}>{m}</option>
                                ))}
                            </select>
                        </div>
                        <div className="form-group" style={{ marginBottom: 0 }}>
                            <label className="form-label-upper">CATEGORY</label>
                            <select className="form-select">
                                <option>🍽️ Dining Out</option>
                                <option>🚗 Transportation</option>
                                <option>🎬 Entertainment</option>
                                <option>🏠 Utilities</option>
                                <option>🛒 Shopping</option>
                                <option>📦 Other</option>
                            </select>
                        </div>
                    </div>

                    <div className="form-group">
                        <label className="form-label-upper">SPLIT METHOD</label>
                        <div className="split-options">
                            {['equal', 'custom', 'percentage'].map((type) => (
                                <button
                                    key={type}
                                    type="button"
                                    className={`split-option ${splitType === type ? 'active' : ''}`}
                                    onClick={() => setSplitType(type)}
                                >
                                    {type.charAt(0).toUpperCase() + type.slice(1)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="split-members-list">
                        {members.map((m, i) => (
                            <div key={m} className="split-member-item">
                                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                                    <div
                                        className="avatar"
                                        style={{
                                            background: i % 2 === 0 ? 'var(--purple-200)' : 'var(--green-200)',
                                            color: i % 2 === 0 ? 'var(--purple-700)' : 'var(--green-700)',
                                            width: 36, height: 36, fontSize: 13,
                                        }}
                                    >
                                        {m.charAt(0).toUpperCase()}
                                    </div>
                                    <strong style={{ fontSize: 14 }}>{m}</strong>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                    <span style={{ fontWeight: 600, fontSize: 14, color: 'var(--text-secondary)' }}>₹0.00</span>
                                    <span style={{ color: 'var(--green-500)', fontSize: 16 }}>✓</span>
                                </div>
                            </div>
                        ))}
                    </div>

                    <button type="submit" className="form-submit" style={{ borderRadius: 28, marginTop: 20 }}>
                        ✂️ Post Expense
                    </button>

                    <p style={{ textAlign: 'center', marginTop: 12, fontSize: 11, color: 'var(--text-secondary)', textTransform: 'uppercase' }}>
                        INSTANT NOTIFICATION WILL BE SENT TO {members.length} MEMBERS
                    </p>
                </form>
            </Card>
        </div>
    );
};

export default AddExpense;
